class PointCloudException(Exception):
    """A generic exception for point clouds."""


class FieldAlreadyExists(PointCloudException):
    """Exception raised when trying to create a field to a PointCloud with
    an already existing field name.
    """


class InvalidFieldName(PointCloudException):
    """Exception raised when trying to create a field with a name used by an
    existing method or attribute.
    """


class EmptyPointCloudException(PointCloudException, ValueError):
    """And exception raised when an illegal operation is performed on empty point
    cloud.
    """

    def __init__(self, operation: str) -> None:
        self.operation: str = operation

    def __str__(self) -> str:
        return f"Invalid operation '{self.operation}' on empty point cloud"


class HeterogeneousFieldsException(PointCloudException):
    """An exception raised when trying to merge clouds with heterogeneous fields"""
